void reverse(int nums[], int start, int end) {
    while (start < end) {
        int temp = nums[start];
        nums[start] = nums[end];
        nums[end] = temp;
        start++;
        end--;
    }
}

// Function to rotate array by k steps
void rotate(int nums[], int n, int k) {
    if (n == 0) return; // Edge case: empty array
    k = k % n;          // Handle k > n

    reverse(nums, 0, n - 1);
    reverse(nums, 0, k - 1);
    reverse(nums, k, n - 1);
}

